using LFG.Collezioni;
using LFG.Helpers;
using System;
using System.Collections.Generic;
using System.Threading.Tasks;
using JetBrains.Annotations;
using Volo.Abp.Domain.Services;
using Volo.Abp.Domain.Repositories;

namespace LFG.Prodotti;

public class ProdottoManager : ProdottoManagerBase
{
    //<suite-custom-code-autogenerated>
    public ProdottoManager(IProdottoRepository prodottoRepository) : base(prodottoRepository)
    {
    }

    //</suite-custom-code-autogenerated>
    public override Task<Prodotto> CreateAsync(List<Guid> collezionesIds, Guid? categoriaId, string nome, string prezzo, string sezione, string? descrizione = null, string? codiceSku = null)
    {
        return base.CreateAsync(collezionesIds, categoriaId, nome, PrezzoHelper.NormalizzaRaw(prezzo), sezione, descrizione, codiceSku);
    }

    public override Task<Prodotto> UpdateAsync(Guid id, List<Guid> collezionesIds, Guid? categoriaId, string nome, string prezzo, string sezione, string? descrizione = null, string? codiceSku = null, [CanBeNull] string? concurrencyStamp = null)
    {
        return base.UpdateAsync(id, collezionesIds, categoriaId, nome, PrezzoHelper.NormalizzaRaw(prezzo), sezione, descrizione, codiceSku, concurrencyStamp);
    }
}